#!/usr/bin/env node
/**
 * .github/scripts/generate-schema-docs.js
 * Genera docs/database/schema.md desde las migraciones SQL.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '../..');
const migrationsDir = path.join(ROOT, 'supabase/migrations');
const outDir = path.join(ROOT, 'docs/database');

if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });

let content = '# Database Schema\n\n*Auto-generated by CI — do not edit manually*\n\n';

if (fs.existsSync(migrationsDir)) {
  const migrations = fs.readdirSync(migrationsDir).filter((f) => f.endsWith('.sql')).sort();
  for (const m of migrations) {
    const sql = fs.readFileSync(path.join(migrationsDir, m), 'utf8');
    const tableName = m.replace(/^\d+_crear_tabla_/, '').replace('.sql', '');
    content += `## ${tableName}\n\n\`\`\`sql\n${sql.trim()}\n\`\`\`\n\n`;
  }
}

fs.writeFileSync(path.join(outDir, 'schema.md'), content);
console.log('✅ docs/database/schema.md generated');
